var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하아…. 믿을 수 없어.","JPN":"はあ……信じられない。","ENG":"*Sigh...* This is ridiculous.","TWN":"蛤……真不敢相信。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"최고의 엘리트가 되어야 할 내가 이런 평범한 수업이나 들어야 한다니….","JPN":"最高のエリートになるはずの私が、こんな平凡な授業を受けないといけないなんて……","ENG":"I can't believe an elite like me has to take this boring class...","TWN":"要成為最頂尖精英的我，居然還要上這種普通的課……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"방금 그 말. 선생님이 들으셨으면 엄청 슬퍼하셨을거야.","JPN":"今の言葉、先生が聞いたらすごく悲しんでたよ。","ENG":"You know, the teacher would be so heartbroken to hear that.","TWN":"剛才那句話，如果老師聽到了會非常傷心的。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"지금 너하고 나밖에 없으니까 상관없잖아.","JPN":"でも今はあんたと私しかいないから別にいいんじゃない。","ENG":"It's only you and me, so it's fine.","TWN":"現在這裡只有你和我，所以無所謂吧。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"난 빨리 모의 전투 랭킹 1위를 달성해야 한다고.","JPN":"私は早く模擬戦闘でランキング1位を取らないといけないの。","ENG":"I need to reach number 1 on the simulation training leaderboard as fast as possible.","TWN":"我必須儘快達到模擬戰鬥的排名第一。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이대로 가다간, 너 처럼 지나가는 학생A나 다름 없어진단 말이야.","JPN":"このままだと、あんたみたいに通りすがりの生徒Aになっちゃう。","ENG":"At this rate, I'll be just another student in the crowd like you.","TWN":"照這樣下去，我就會變成像你一樣的路人甲了。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"야 넌 꼭 말을 그런 식으로 해야겠니?","JPN":"そんな言い方、ひどいじゃない！","ENG":"Hey, was it necessary to say it like that?","TWN":"喂，你一定要那樣說話嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흐, 흥…….","JPN":"ふ、ふん……","ENG":"H-hmph...","TWN":"哼，哼……"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"후~ 이대로 내버려두면 끝도 없겠어.","JPN":"ふう……こんなやり取り、きりがないね。","ENG":"*Sigh* It'll never end if I leave her like this.","TWN":"呼～這樣下去沒完沒了。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"……있지. 나이엘은 지금까지 엄청 열심히 해왔잖아.","JPN":"……ねえ、ナイエルは今まですごく頑張ってきたじゃない。","ENG":"...Hey. You've done so much until now, Naielle.","TWN":"……你看，奈爾一直以來都非常努力。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오래 본 사이니까 잘 알아. 그 점은 나도 높이 사고 있어.","JPN":"長い付き合いだからわかる。あなたのそんなところはあたしもすごいと思うよ。","ENG":"I know because we've known each other for a long time. And I think highly of that part of you.","TWN":"因為我們認識很久了，所以我很了解你。這一點我也很看重。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러니까 가끔은 좀 쉬어 가는 것도 좋지 않을까?","JPN":"だから、たまには少し一息ついてもいいんじゃないかな？","ENG":"So, wouldn't it be good to take a break sometimes?","TWN":"所以偶爾休息一下也不錯吧？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오늘 수업 때 하루 종일 자고 있던 것도, 특별히 못 본 거로 해줄게!","JPN":"今日の授業中ずっと寝てたことも、特別に目を瞑ってあげるから！","ENG":"I'll even pretend I didn't see you sleeping all day during class today!","TWN":"今天上課你一直在睡覺的事，我就當作沒看見吧！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이게 지금 날 놀리겠다는 거야 뭐야?","JPN":"それって私をバカにしてない？","ENG":"Are you mocking me or something?","TWN":"你這是在耍我嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아참, 그러고 보니 곧 새로운 시스템이 도입된다고 들었는데……!","JPN":"あ、そういえば近いうちに新しいシステムが導入されるらしいけど……","ENG":"Oh, right. I heard a new system will be implemented soon...!","TWN":"啊，對了，聽說馬上要引入新的系統了……！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"너도 나름 학생회원이잖아. 뭔가 아는 거 없어?","JPN":"あんたも一応生徒会の一員でしょ？　なにか知ってる？","ENG":"You're in the Student Council, right? Don't you know anything about it?","TWN":"你也是學會成員吧，難道你什麼都不知道嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그게 지금 물어보는 태도야?","JPN":"それが人に質問する態度なの？","ENG":"How about you ask a little more politely?","TWN":"你現在這是問問題的態度嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아는 게 있으면 전부 말해!","JPN":"知ってるなら全部話してよ！","ENG":"Tell me everything you know!","TWN":"知道什麼就全都說出來！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으앗, 지, 진정해!","JPN":"わあ、お、落ち着いて！","ENG":"Eesh, c-calm down!","TWN":"啊，冷、冷靜！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"휴……. 어쩔 수 없지.","JPN":"はあ……仕方ないね。","ENG":"*Sigh* Fine.","TWN":"呼……沒辦法了。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"지금까지 성실히 봉사활동 했으니까 알려줄게. 진짜 비밀이다?\xA0","JPN":"今まで真面目にボランティアやってくれたから、教えてあげる。他の人には内緒だからね？\xA0","ENG":"I'll tell you only because you did well in your volunteering. But you have to keep it a secret, okay?\xA0","TWN":"到目前為止你一直在認真做志工活動，所以我才告訴你。這可是個真正的秘密喔？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오늘 아카데미에 새로운 선생님 <color=#ffd34c>두 분</color>이 오시는 건 알지?","JPN":"今日アカデミーに新しい先生が<color=#ffd34c>2人</color>来るってこと、知ってるよね？","ENG":"You know how there are <color=#ffd34c>two</color> new teachers coming to the Academy today, right?","TWN":"今天有<color=#ffd34c>兩位</color>新老師要來學院，你知道嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>판도라</color> 회사. 들어본 적 있어?","JPN":"<color=#ffd34c>パンドラ</color>って会社、聞いたことある？","ENG":"Have you ever heard of a company called <color=#ffd34c>Pandora</color>?","TWN":"<color=#ffd34c>潘朵拉</color>公司。聽說過嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"설마 그 게임 회사 말하는 거야?","JPN":"まさかあのゲーム会社のこと？","ENG":"Are you talking about that game company?","TWN":"難道你在說那家遊戲公司嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>맞아, 카운터즈 시리즈를 만든 그 회사!</color>","JPN":"<color=#ffd34c>そうだよ。カウンターズシリーズを作ったあの会社！</color>","ENG":"<color=#ffd34c>Yeah, the company that made the Counters series!</color>","TWN":"<color=#ffd34c>沒錯，就是製作了制裁者系列的那家公司！</color>"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};